import{_ as d,o,c as t,ag as c}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"第3章 统一沙盒 API 设计","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/03-api-design.md","filePath":"chapters/03-api-design.md"}'),a={name:"chapters/03-api-design.md"};function s(r,e,i,n,l,p){return o(),t("div",null,[...e[0]||(e[0]=[c(`<h1 id="第3章-统一沙盒-api-设计" tabindex="-1">第3章 统一沙盒 API 设计 <a class="header-anchor" href="#第3章-统一沙盒-api-设计" aria-label="Permalink to &quot;第3章 统一沙盒 API 设计&quot;">​</a></h1><blockquote><p>&quot;A good API is not just an interface — it is a contract that shapes how every component in the system communicates.&quot; — Joshua Bloch</p></blockquote><h2 id="protocol-first-从规范到实现" tabindex="-1">Protocol-First：从规范到实现 <a class="header-anchor" href="#protocol-first-从规范到实现" aria-label="Permalink to &quot;Protocol-First：从规范到实现&quot;">​</a></h2><p>在第1章中我们提到，OpenSandbox 的核心设计哲学是 Protocol-First。这意味着 API 规范不是从代码中生成的，而是反过来 — 代码是从规范中派生的。<code>specs/</code> 目录下的三份 OpenAPI 文件是整个系统的 <strong>single source of truth</strong>。</p><p>为什么选择这种方式？因为 OpenSandbox 面对的是一个天然的多语言、多组件系统。4 种语言的 SDK、Python 编写的 Lifecycle Server、Go 编写的 execd 守护进程和 egress 代理 — 如果每个组件各自定义接口，版本漂移几乎不可避免。统一的 OpenAPI 规范消除了这种风险。</p><h2 id="三份规范-三个关注点" tabindex="-1">三份规范，三个关注点 <a class="header-anchor" href="#三份规范-三个关注点" aria-label="Permalink to &quot;三份规范，三个关注点&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>specs/</span></span>
<span class="line"><span>├── sandbox-lifecycle.yml    # 沙盒生命周期管理</span></span>
<span class="line"><span>├── execd-api.yaml           # 容器内代码与命令执行</span></span>
<span class="line"><span>└── egress-api.yaml          # 出口网络策略控制</span></span></code></pre></div><p>这三份规范对应三个不同的网络边界和运行主体：</p><p><strong>sandbox-lifecycle.yml</strong> 定义了 Lifecycle Server 暴露给 SDK 的 API。这是外部客户端唯一直接交互的接口，负责沙盒的创建、查询、删除、暂停、恢复和续期。</p><p><strong>execd-api.yaml</strong> 定义了 execd 守护进程在容器内部暴露的 API。SDK 通常不直接调用这些端点，而是通过 Lifecycle Server 的 proxy 路由（<code>/sandboxes/{id}/proxy/{port}/...</code>）透传。</p><p><strong>egress-api.yaml</strong> 定义了 egress sidecar 的策略管理接口。这是一个仅内部使用的 API，运行在 <code>localhost:18080</code>，用于运行时动态调整出口网络规则。</p><h2 id="生命周期-api-的-10-个路由" tabindex="-1">生命周期 API 的 10 个路由 <a class="header-anchor" href="#生命周期-api-的-10-个路由" aria-label="Permalink to &quot;生命周期 API 的 10 个路由&quot;">​</a></h2><p><code>server/src/api/lifecycle.py</code> 实现了 10 个路由，全部注册在 <code>/</code> 和 <code>/v1</code> 两个前缀下：</p><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>用途</th><th>状态码</th></tr></thead><tbody><tr><td>POST</td><td><code>/sandboxes</code></td><td>创建沙盒</td><td>202</td></tr><tr><td>GET</td><td><code>/sandboxes</code></td><td>列出沙盒（支持分页和过滤）</td><td>200</td></tr><tr><td>GET</td><td><code>/sandboxes/{id}</code></td><td>获取沙盒详情</td><td>200</td></tr><tr><td>DELETE</td><td><code>/sandboxes/{id}</code></td><td>删除沙盒</td><td>204</td></tr><tr><td>POST</td><td><code>/sandboxes/{id}/pause</code></td><td>暂停沙盒</td><td>202</td></tr><tr><td>POST</td><td><code>/sandboxes/{id}/resume</code></td><td>恢复沙盒</td><td>202</td></tr><tr><td>POST</td><td><code>/sandboxes/{id}/renew-expiration</code></td><td>续期</td><td>200</td></tr><tr><td>GET</td><td><code>/sandboxes/{id}/endpoints/{port}</code></td><td>获取访问端点</td><td>200</td></tr><tr><td>*</td><td><code>/sandboxes/{id}/proxy/{port}/{path}</code></td><td>代理请求</td><td>透传</td></tr></tbody></table><p>一个值得注意的设计选择是 <strong>异步创建语义</strong>。CREATE、PAUSE、RESUME 三个操作都返回 HTTP 202 Accepted 而非 200 OK，表示操作已接受但尚未完成。客户端需要轮询 GET 接口获取最终状态。这个决策源于实际的延迟特性 — 创建一个沙盒可能需要拉取镜像、分配资源、等待 Pod 就绪，这些操作可能耗时数十秒，同步等待会阻塞客户端。</p><p>沙盒状态机涵盖 7 个状态：<code>Pending</code>、<code>Running</code>、<code>Pausing</code>、<code>Paused</code>、<code>Stopping</code>、<code>Terminated</code>、<code>Failed</code>。其中 <code>Pausing</code> 和 <code>Stopping</code> 是过渡态，反映了异步操作的中间过程。</p><h2 id="execd-执行-api-三大能力域" tabindex="-1">execd 执行 API：三大能力域 <a class="header-anchor" href="#execd-执行-api-三大能力域" aria-label="Permalink to &quot;execd 执行 API：三大能力域&quot;">​</a></h2><p>execd 守护进程暴露的 API 按功能域划分为三大类：</p><h3 id="代码执行" tabindex="-1">代码执行 <a class="header-anchor" href="#代码执行" aria-label="Permalink to &quot;代码执行&quot;">​</a></h3><ul><li><code>POST /code/context</code> — 创建执行上下文</li><li><code>POST /code</code> — 执行代码（支持 SSE 流式输出）</li><li><code>DELETE /code</code> — 中断正在执行的代码</li><li><code>GET /code/contexts</code> — 列出活跃上下文</li><li><code>DELETE /code/contexts</code> — 清除指定语言的所有上下文</li></ul><p>代码执行基于 Jupyter 内核协议，这意味着每个&quot;上下文&quot;本质上是一个持久化的内核会话，变量和状态在多次执行间保持。这对 AI 代码执行场景至关重要 — Agent 通常需要在多轮对话中逐步构建和调试代码。</p><h3 id="命令执行" tabindex="-1">命令执行 <a class="header-anchor" href="#命令执行" aria-label="Permalink to &quot;命令执行&quot;">​</a></h3><ul><li><code>POST /command</code> — 执行 shell 命令（前台/后台模式）</li><li><code>DELETE /command</code> — 中断命令</li><li><code>GET /command/status/{id}</code> — 查询命令状态</li><li><code>GET /command/{id}/logs</code> — 获取后台命令输出（基于游标分页）</li></ul><p>命令执行区分前台和后台模式，后台命令通过游标分页获取日志，这避免了长时间运行命令的超时问题。前台命令同步返回输出和退出码，适合快速的一次性操作；后台命令立即返回命令 ID，客户端通过 <code>GET /command/status/{id}</code> 轮询状态，再用 <code>GET /command/{id}/logs</code> 获取输出。这种双模式设计贴合了 AI Agent 的实际使用模式 — 短命令（如 <code>ls</code>、<code>pip install</code>）用前台模式获得即时反馈，长命令（如模型训练、数据处理）用后台模式避免连接超时。</p><h3 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h3><ul><li><code>GET /files/info</code>、<code>DELETE /files</code>、<code>POST /files/permissions</code></li><li><code>POST /files/mv</code>、<code>GET /files/search</code>、<code>POST /files/replace</code></li><li><code>POST /files/upload</code>、<code>GET /files/download</code></li><li><code>POST /directories</code>、<code>DELETE /directories</code></li></ul><p>文件操作 API 共 10 个端点，覆盖了元数据查询、CRUD、权限管理、搜索替换和批量上传下载。<code>GET /files/download</code> 支持 HTTP Range 请求，适合大文件的断点续传。</p><p>此外，<code>GET /metrics</code> 和 <code>GET /metrics/watch</code>（SSE）提供 CPU 和内存的实时监控能力。快照接口返回瞬时值，适合轮询场景；而 SSE 流式接口推送持续的指标更新，适合在前端仪表盘中展示实时资源消耗趋势。对于 RL 训练等批量场景，监控接口还可以帮助调度系统判断沙盒是否处于空闲状态，从而做出资源回收决策。</p><h2 id="三层认证机制" tabindex="-1">三层认证机制 <a class="header-anchor" href="#三层认证机制" aria-label="Permalink to &quot;三层认证机制&quot;">​</a></h2><p>OpenSandbox 在不同网络边界实施了不同的认证策略：</p><p><strong>第一层：API Key 认证</strong>。SDK 访问 Lifecycle Server 时，必须在请求头中携带 <code>OPEN-SANDBOX-API-KEY</code>。<code>server/src/middleware/auth.py</code> 中的 <code>AuthMiddleware</code> 负责验证。部分路径被豁免认证，包括 <code>/health</code>、<code>/docs</code>、<code>/redoc</code> 和 proxy 路由（proxy 路由依赖 execd 自身的认证）。</p><p><strong>第二层：execd Token</strong>。容器内的 execd 守护进程使用 <code>X-EXECD-ACCESS-TOKEN</code> 头进行认证，防止同一网络中的其他容器未授权访问执行 API。</p><p><strong>第三层：egress Token</strong>。egress sidecar 使用 <code>OPENSANDBOX-EGRESS-AUTH</code> 头保护策略管理接口，确保只有 Lifecycle Server 能修改出口规则。</p><p>这种分层设计体现了最小权限原则 — 每一层只暴露必要的认证信息，避免单一 token 泄漏导致全面失控。</p><h2 id="错误规范化" tabindex="-1">错误规范化 <a class="header-anchor" href="#错误规范化" aria-label="Permalink to &quot;错误规范化&quot;">​</a></h2><p>一个成熟的 API 需要结构化的错误处理。OpenSandbox 定义了分层的错误码体系：Docker 后端 18 个错误码、Kubernetes 后端 6 个、通用错误 4 个、卷操作错误 22 个。所有错误响应都遵循统一的 <code>ErrorResponse</code> schema，包含错误码、人类可读消息和可选的详情字段。</p><p>这种设计使得 SDK 层可以对不同运行时后端的错误进行统一处理，而不需要了解底层实现细节。例如，无论 Docker 返回 <code>CONTAINER_NOT_FOUND</code> 还是 Kubernetes 返回 <code>POD_NOT_FOUND</code>，SDK 都能映射为语义一致的&quot;沙盒不存在&quot;错误。</p><h2 id="双前缀注册" tabindex="-1">双前缀注册 <a class="header-anchor" href="#双前缀注册" aria-label="Permalink to &quot;双前缀注册&quot;">​</a></h2><p>路由同时注册在 <code>/</code> 和 <code>/v1</code> 前缀下，这是一个面向未来的兼容性设计。当前版本的 API 在两个前缀下行为完全一致。未来如果引入破坏性变更，可以在 <code>/v2</code> 前缀下注册新版本，同时保持 <code>/v1</code> 的向后兼容。无版本前缀的 <code>/</code> 始终指向最新版本，方便快速上手。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>OpenSandbox 的 API 设计以三份 OpenAPI 规范为核心，覆盖了沙盒生命周期、容器内执行和出口策略三个关注点。异步创建语义、基于 Jupyter 内核的代码执行、三层认证机制和分层错误码体系，这些设计选择都源于 AI 应用沙盒的实际需求。统一的协议契约使得 4 种语言的 SDK 和 2 种运行时后端能够保持一致的行为语义。</p>`,41)])])}const P=d(a,[["render",s]]);export{u as __pageData,P as default};
